import React, { useState, useMemo } from "react";
import { useNewsFeed } from "./hooks/useNewsFeed";
import { NewsCard } from "./components/NewsCard";
import { LoadingSkeleton } from "./components/LoadingSkeleton";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { ScrollArea } from "@/components/ui/scroll-area";
import { RefreshCw, Search, AlertCircle, Shield, Rss } from "lucide-react";
import { formatDistanceToNow } from "date-fns";
import { motion, AnimatePresence } from "framer-motion";

const FILTER_CATEGORIES = [
  "All",
  "Conflict",
  "Navy",
  "Air Force",
  "Army",
  "Missile",
  "NATO",
  "Intel",
  "Cyber",
  "Space",
  "Budget",
  "Diplomacy",
  "Nuclear",
] as const;

const ACTIVE_CATEGORY_COLORS: Record<string, string> = {
  "All": "bg-zinc-100 text-zinc-900",
  "Navy": "bg-blue-500 text-white",
  "Air Force": "bg-sky-500 text-white",
  "Army": "bg-green-500 text-white",
  "Space": "bg-purple-500 text-white",
  "Cyber": "bg-cyan-500 text-white",
  "Intel": "bg-amber-500 text-white",
  "NATO": "bg-indigo-500 text-white",
  "Missile": "bg-red-500 text-white",
  "Nuclear": "bg-orange-500 text-white",
  "Budget": "bg-emerald-500 text-white",
  "Conflict": "bg-rose-500 text-white",
  "Diplomacy": "bg-teal-500 text-white",
};

export default function App() {
  const { articles, loading, error, lastUpdated, refresh } = useNewsFeed();
  const [search, setSearch] = useState("");
  const [activeCategory, setActiveCategory] = useState<string>("All");
  const [refreshing, setRefreshing] = useState(false);

  const filteredArticles = useMemo(() => {
    let filtered = articles;

    if (activeCategory !== "All") {
      filtered = filtered.filter((a) => a.category === activeCategory);
    }

    if (search.trim()) {
      const q = search.toLowerCase();
      filtered = filtered.filter(
        (a) =>
          a.title.toLowerCase().includes(q) ||
          a.source.toLowerCase().includes(q) ||
          a.description.toLowerCase().includes(q)
      );
    }

    return filtered;
  }, [articles, activeCategory, search]);

  const categoryCounts = useMemo(() => {
    const counts: Record<string, number> = { All: articles.length };
    for (const a of articles) {
      const cat = a.category || "Defense";
      counts[cat] = (counts[cat] || 0) + 1;
    }
    return counts;
  }, [articles]);

  const handleRefresh = async () => {
    setRefreshing(true);
    await refresh();
    setTimeout(() => setRefreshing(false), 600);
  };

  return (
    <div className="w-full h-full flex flex-col overflow-hidden">
      {/* Header Bar */}
      <div className="flex-shrink-0 px-4 pt-3 pb-2 border-b border-zinc-800 bg-zinc-950/80">
        {/* Top row: status + refresh */}
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <Shield size={15} className="text-emerald-400" />
            <span className="text-[11px] text-zinc-500 uppercase tracking-widest font-semibold">
              Live Feed
            </span>
            {!loading && articles.length > 0 && (
              <Badge variant="outline" className="text-[10px] border-zinc-700 text-zinc-400 px-1.5 py-0">
                {articles.length} articles
              </Badge>
            )}
          </div>
          <div className="flex items-center gap-2">
            {lastUpdated && (
              <span className="text-[10px] text-zinc-600">
                Updated {formatDistanceToNow(lastUpdated, { addSuffix: true })}
              </span>
            )}
            <Button
              variant="ghost"
              size="sm"
              onClick={handleRefresh}
              disabled={loading}
              className="h-7 w-7 p-0 text-zinc-400 hover:text-zinc-100"
            >
              <RefreshCw
                size={13}
                className={refreshing ? "animate-spin" : ""}
              />
            </Button>
          </div>
        </div>

        {/* Search */}
        <div className="relative mb-3">
          <Search
            size={13}
            className="absolute left-2.5 top-1/2 -translate-y-1/2 text-zinc-500"
          />
          <Input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search headlines, sources..."
            className="h-8 pl-8 text-xs bg-zinc-900 border-zinc-800 focus:border-zinc-600 text-zinc-200 placeholder:text-zinc-600"
          />
        </div>

        {/* Category Filters */}
        <div className="flex gap-1 overflow-x-auto pb-1 scrollbar-none">
          {FILTER_CATEGORIES.map((cat) => {
            const count = categoryCounts[cat] || 0;
            const isActive = activeCategory === cat;
            if (cat !== "All" && count === 0) return null;

            return (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`flex-shrink-0 px-2 py-0.5 text-[11px] font-medium transition-all duration-150 border ${
                  isActive
                    ? `${ACTIVE_CATEGORY_COLORS[cat] || "bg-zinc-100 text-zinc-900"} border-transparent`
                    : "border-zinc-800 text-zinc-500 hover:text-zinc-300 hover:border-zinc-700 bg-transparent"
                }`}
              >
                {cat}
                {count > 0 && (
                  <span className={`ml-1 ${isActive ? "opacity-70" : "text-zinc-600"}`}>
                    {count}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-auto">
        {loading && articles.length === 0 ? (
          <LoadingSkeleton />
        ) : error && articles.length === 0 ? (
          <div className="p-4">
            <Alert className="border-red-900/50 bg-red-950/30">
              <AlertCircle className="h-4 w-4 text-red-400" />
              <AlertDescription className="text-red-300 text-xs">
                {error}
              </AlertDescription>
            </Alert>
            <Button
              variant="outline"
              size="sm"
              onClick={handleRefresh}
              className="mt-3 text-xs border-zinc-700"
            >
              <RefreshCw size={12} className="mr-1.5" />
              Retry
            </Button>
          </div>
        ) : filteredArticles.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 text-zinc-500">
            <Rss size={24} className="mb-2 text-zinc-600" />
            <p className="text-xs">No articles match your filter</p>
            <button
              onClick={() => {
                setSearch("");
                setActiveCategory("All");
              }}
              className="text-[11px] text-zinc-400 hover:text-zinc-200 mt-1 underline underline-offset-2"
            >
              Clear filters
            </button>
          </div>
        ) : (
          <div className="divide-y divide-zinc-800/50">
            <AnimatePresence mode="popLayout">
              {filteredArticles.map((article, i) => (
                <NewsCard key={article.id} article={article} index={i} />
              ))}
            </AnimatePresence>
          </div>
        )}

        {/* Loading overlay for refresh */}
        {loading && articles.length > 0 && (
          <div className="sticky bottom-0 left-0 right-0 p-2 bg-zinc-950/90 border-t border-zinc-800 flex items-center justify-center gap-2">
            <RefreshCw size={12} className="animate-spin text-zinc-400" />
            <span className="text-[11px] text-zinc-400">Updating feed...</span>
          </div>
        )}
      </div>
    </div>
  );
}

