import { useState, useEffect, useCallback } from "react";
import { formatDistanceToNow } from "date-fns";
import { RefreshCw, Search, Shield, ExternalLink, AlertTriangle, Globe } from "lucide-react";

interface NewsItem {
  title: string;
  link: string;
  pubDate: string;
  source: string;
  category: string;
}

const RSS_FEEDS = [
  { url: "https://feeds.feedburner.com/defense-news/home", source: "Defense News" },
  { url: "https://news.google.com/rss/search?q=military+conflict+war&hl=en-US&gl=US&ceid=US:en", source: "Google News" },
  { url: "https://www.aljazeera.com/xml/rss/all.xml", source: "Al Jazeera" },
];

const PROXY = "/api/proxy?url=";

function parseRSS(xml: string, source: string): NewsItem[] {
  const parser = new DOMParser();
  const doc = parser.parseFromString(xml, "text/xml");
  const items = doc.querySelectorAll("item");
  const results: NewsItem[] = [];
  items.forEach((item) => {
    const title = item.querySelector("title")?.textContent || "";
    const link = item.querySelector("link")?.textContent || "";
    const pubDate = item.querySelector("pubDate")?.textContent || "";
    const cat = item.querySelector("category")?.textContent || "General";
    const keywords = ["military", "war", "conflict", "army", "navy", "missile", "nato", "defense", "weapon", "troops", "strike", "bomb", "attack", "soldier", "combat", "airstrike", "drone", "ukraine", "russia", "gaza", "israel", "iran"];
    const isRelevant = source !== "Google News" || keywords.some(k => title.toLowerCase().includes(k));
    if (isRelevant && title) {
      results.push({ title, link, pubDate, source, category: cat });
    }
  });
  return results;
}

function classifyCategory(title: string): string {
  const t = title.toLowerCase();
  if (t.match(/navy|naval|ship|submarine|fleet/)) return "Navy";
  if (t.match(/air force|jet|fighter|bomber|aircraft/)) return "Air Force";
  if (t.match(/army|troops|soldier|infantry|tank/)) return "Army";
  if (t.match(/missile|rocket|icbm|ballistic/)) return "Missile";
  if (t.match(/nato|alliance/)) return "NATO";
  if (t.match(/cyber|hack|digital/)) return "Cyber";
  if (t.match(/nuclear|nuke|atomic/)) return "Nuclear";
  if (t.match(/drone|uav|unmanned/)) return "Drone";
  if (t.match(/intel|spy|surveillance/)) return "Intel";
  return "Conflict";
}

const CATEGORY_COLORS: Record<string, string> = {
  Navy: "bg-blue-500/20 text-blue-400",
  "Air Force": "bg-sky-500/20 text-sky-400",
  Army: "bg-green-500/20 text-green-400",
  Missile: "bg-red-500/20 text-red-400",
  NATO: "bg-indigo-500/20 text-indigo-400",
  Cyber: "bg-purple-500/20 text-purple-400",
  Nuclear: "bg-yellow-500/20 text-yellow-400",
  Drone: "bg-orange-500/20 text-orange-400",
  Intel: "bg-teal-500/20 text-teal-400",
  Conflict: "bg-zinc-500/20 text-zinc-400",
};

export default function App() {
  const [news, setNews] = useState<NewsItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState("All");

  const fetchNews = useCallback(async () => {
    setLoading(true);
    const allItems: NewsItem[] = [];
    await Promise.allSettled(
      RSS_FEEDS.map(async (feed) => {
        try {
          const res = await fetch(PROXY + encodeURIComponent(feed.url));
          const text = await res.text();
          allItems.push(...parseRSS(text, feed.source));
        } catch {}
      })
    );
    allItems.forEach((item) => { item.category = classifyCategory(item.title); });
    allItems.sort((a, b) => new Date(b.pubDate).getTime() - new Date(a.pubDate).getTime());
    setNews(allItems);
    setLoading(false);
  }, []);

  useEffect(() => { fetchNews(); const i = setInterval(fetchNews, 120000); return () => clearInterval(i); }, [fetchNews]);

  const categories = ["All", ...Object.keys(CATEGORY_COLORS)];
  const filtered = news.filter((n) => {
    if (filter !== "All" && n.category !== filter) return false;
    if (search && !n.title.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  return (
    <div className="h-full flex flex-col bg-zinc-950 text-zinc-100">
      <div className="flex items-center gap-2 px-3 py-2 border-b border-zinc-800">
        <Shield className="w-4 h-4 text-red-400 shrink-0" />
        <div className="relative flex-1">
          <Search className="w-3 h-3 absolute left-2 top-1/2 -translate-y-1/2 text-zinc-500" />
          <input className="w-full bg-zinc-900 border border-zinc-800 rounded text-xs pl-7 pr-2 py-1 text-zinc-300 placeholder:text-zinc-600 focus:outline-none focus:border-zinc-600" placeholder="Search news..." value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>
        <button onClick={fetchNews} className="p-1 hover:bg-zinc-800 rounded" title="Refresh">
          <RefreshCw className={`w-3.5 h-3.5 text-zinc-400 ${loading ? "animate-spin" : ""}`} />
        </button>
      </div>
      <div className="flex gap-1 px-3 py-1.5 overflow-x-auto border-b border-zinc-800/50">
        {categories.map((cat) => (
          <button key={cat} onClick={() => setFilter(cat)} className={`px-2 py-0.5 rounded text-[10px] font-medium whitespace-nowrap transition-colors ${filter === cat ? "bg-zinc-100 text-zinc-900" : "bg-zinc-800/50 text-zinc-500 hover:text-zinc-300"}`}>
            {cat}
          </button>
        ))}
      </div>
      <div className="flex-1 overflow-y-auto">
        {loading && news.length === 0 ? (
          <div className="flex items-center justify-center h-32 text-zinc-500 text-xs">Loading feeds...</div>
        ) : filtered.length === 0 ? (
          <div className="flex items-center justify-center h-32 text-zinc-500 text-xs">No matching articles</div>
        ) : (
          <div className="divide-y divide-zinc-800/50">
            {filtered.slice(0, 50).map((item, i) => (
              <a key={i} href={item.link} target="_blank" rel="noopener noreferrer" className="block px-3 py-2 hover:bg-zinc-900/50 transition-colors group">
                <div className="flex items-start gap-2">
                  <div className="flex-1 min-w-0">
                    <p className="text-xs text-zinc-200 leading-snug group-hover:text-white line-clamp-2">{item.title}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <span className={`px-1.5 py-0.5 rounded text-[9px] font-medium ${CATEGORY_COLORS[item.category] || CATEGORY_COLORS.Conflict}`}>{item.category}</span>
                      <span className="text-[10px] text-zinc-600">{item.source}</span>
                      {item.pubDate && <span className="text-[10px] text-zinc-600">{formatDistanceToNow(new Date(item.pubDate), { addSuffix: true })}</span>}
                    </div>
                  </div>
                  <ExternalLink className="w-3 h-3 text-zinc-700 group-hover:text-zinc-400 shrink-0 mt-0.5" />
                </div>
              </a>
            ))}
          </div>
        )}
      </div>
      <div className="px-3 py-1 border-t border-zinc-800 text-[10px] text-zinc-600 flex justify-between">
        <span>{filtered.length} articles</span>
        <span>Auto-refresh 2min</span>
      </div>
    </div>
  );
}

