export default function App() {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<maplibregl.Map | null>(null);
  const markersRef = useRef<maplibregl.Marker[]>([]);
  const [ready, setReady] = useState(false);
  const [filterMode, setFilterMode] = useState<"type" | "conflict">("conflict");
  const [hidden, setHidden] = useState<Set<string>>(new Set());

  // Init map once
  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const m = new maplibregl.Map({
      container: containerRef.current,
      style: {
        version: 8,
        sources: {
          carto: {
            type: "raster",
            tiles: [
              "https://a.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png",
              "https://b.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png",
              "https://c.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png",
            ],
            tileSize: 256,
            attribution: '&copy; <a href="https://carto.com">CARTO</a> &copy; <a href="https://www.openstreetmap.org/copyright">OSM</a>',
          },
        },
        layers: [{ id: "carto-tiles", type: "raster", source: "carto", minzoom: 0, maxzoom: 19 }],
      },
      center: [20, 15],
      zoom: 2,
    });

    m.addControl(new maplibregl.NavigationControl(), "bottom-right");
    mapRef.current = m;
    m.on("load", () => setReady(true));

    return () => { m.remove(); mapRef.current = null; };
  }, []);

  // Place native markers when ready or filters change
  useEffect(() => {
    if (!ready || !mapRef.current) return;
    const map = mapRef.current;

    // Remove old markers
    markersRef.current.forEach(m => m.remove());
    markersRef.current = [];

    // Filter events
    const vis = EVENTS.filter(evt => {
      const key = filterMode === "type" ? evt.type : evt.conflict;
      return !hidden.has(key);
    });

    // Create native colored markers
    vis.forEach(evt => {
      const color = filterMode === "type"
        ? (TYPES[evt.type] || "#ffffff")
        : (CONFLICTS[evt.conflict] || "#ffffff");

      // Use native MapLibre marker with color + scale
      // This uses the built-in SVG pin Ã¢â‚¬â€ perfect anchor at the pin tip
      const marker = new maplibregl.Marker({
        color: color,
        scale: 0.65,
      })
        .setLngLat([evt.lng, evt.lat])
        .setPopup(
          new maplibregl.Popup({
            closeButton: true,
            closeOnClick: true,
            maxWidth: "320px",
            offset: 20,
            className: "dark-popup",
          }).setHTML(`
            <div style="font-family:monospace;font-size:12px;background:#18181b;color:#e4e4e7;padding:10px 12px;line-height:1.5;">
              <div style="display:flex;align-items:center;gap:6px;margin-bottom:6px;">
                <span style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${color};flex-shrink:0;box-shadow:0 0 6px ${color};"></span>
                <strong style="color:#fff;font-size:13px;">${evt.type}</strong>
              </div>
              <div style="color:#a1a1aa;font-size:11px;margin-bottom:4px;">${evt.conflict} Ã‚Â· ${evt.date}</div>
              <div style="color:#d4d4d8;margin-bottom:4px;">${evt.location}</div>
              <div style="color:#a1a1aa;font-size:11px;">${evt.description}</div>
              ${evt.casualties ? `<div style="color:#f87171;font-size:11px;margin-top:4px;">Ã¢Å¡Â  ${evt.casualties}</div>` : ""}
            </div>
          `)
        )
        .addTo(map);

      // Add hover glow via CSS filter on the marker element (no transform!)
      const el = marker.getElement();
      el.style.cursor = "pointer";
      el.style.transition = "filter 0.15s ease";
      el.addEventListener("mouseenter", () => {
        el.style.filter = `drop-shadow(0 0 8px ${color}) drop-shadow(0 0 16px ${color})`;
      });
      el.addEventListener("mouseleave", () => {
        el.style.filter = "none";
      });

      markersRef.current.push(marker);
    });
  }, [ready, filterMode, hidden]);

  const toggle = (key: string) => {
    setHidden(prev => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const flyTo = (center: [number, number], zoom: number) => {
    mapRef.current?.flyTo({ center, zoom, duration: 1500 });
  };

  const legendItems = filterMode === "type" ? TYPES : CONFLICTS;
  const visibleCount = EVENTS.filter(evt => !hidden.has(filterMode === "type" ? evt.type : evt.conflict)).length;

  return (
    <div style={{ width: "100%", height: "100vh", position: "relative", background: "#09090b" }}>
      {/* Map */}
      <div ref={containerRef} style={{ position: "absolute", top: 0, left: 0, right: 0, bottom: 0 }} />

      {/* Dark popup & marker styles */}
      <style>{`
        .dark-popup .maplibregl-popup-content {
          background: #18181b !important;
          color: #e4e4e7 !important;
          padding: 0 !important;
          border: 1px solid #3f3f46 !important;
          box-shadow: 0 8px 32px rgba(0,0,0,0.7) !important;
          border-radius: 0 !important;
        }
        .dark-popup .maplibregl-popup-close-button {
          color: #71717a !important;
          font-size: 18px !important;
          padding: 4px 8px !important;
        }
        .dark-popup .maplibregl-popup-close-button:hover { color: #fff !important; }
        .dark-popup .maplibregl-popup-tip {
          border-top-color: #18181b !important;
          border-bottom-color: #18181b !important;
          border-left-color: #18181b !important;
          border-right-color: #18181b !important;
        }
        /* Give native pin markers a subtle drop shadow by default */
        .maplibregl-marker svg {
          filter: drop-shadow(0 1px 3px rgba(0,0,0,0.5));
        }
      `}</style>

      {/* Region buttons */}
      <div style={{
        position: "absolute", top: 10, right: 10, zIndex: 10,
        display: "flex", flexWrap: "wrap", gap: 4, maxWidth: 300,
      }}>
        {REGIONS.map(r => (
          <button
            key={r.label}
            onClick={() => flyTo(r.center, r.zoom)}
            style={{
              background: "#18181bdd", color: "#d4d4d8", border: "1px solid #3f3f46",
              padding: "4px 8px", fontSize: 11, cursor: "pointer", fontFamily: "monospace",
              whiteSpace: "nowrap",
            }}
            onMouseEnter={e => { (e.target as HTMLButtonElement).style.background = "#27272add"; }}
            onMouseLeave={e => { (e.target as HTMLButtonElement).style.background = "#18181bdd"; }}
          >
            {r.label}
          </button>
        ))}
      </div>

      {/* Stats bar */}
      <div style={{
        position: "absolute", top: 10, left: 10, zIndex: 10,
        background: "#18181bee", border: "1px solid #3f3f46", padding: "6px 12px",
        fontFamily: "monospace", fontSize: 11, color: "#a1a1aa",
      }}>
        <span style={{ color: "#fff" }}>{visibleCount}</span> / {EVENTS.length} events visible
      </div>

      {/* Legend */}
      <div style={{
        position: "absolute", bottom: 30, left: 10, zIndex: 10,
        background: "#18181bee", border: "1px solid #3f3f46", padding: "10px 12px",
        fontFamily: "monospace", fontSize: 11, maxHeight: "50vh", overflowY: "auto",
        minWidth: 160,
      }}>
        {/* Toggle buttons */}
        <div style={{ display: "flex", gap: 4, marginBottom: 8 }}>
          {(["conflict", "type"] as const).map(mode => (
            <button
              key={mode}
              onClick={() => { setFilterMode(mode); setHidden(new Set()); }}
              style={{
                flex: 1, padding: "3px 6px", fontSize: 10, cursor: "pointer",
                fontFamily: "monospace", border: "1px solid #3f3f46",
                background: filterMode === mode ? "#3f3f46" : "transparent",
                color: filterMode === mode ? "#fff" : "#71717a",
              }}
            >
              By {mode}
            </button>
          ))}
        </div>

        {/* Items */}
        {Object.entries(legendItems).map(([key, color]) => {
          const isHidden = hidden.has(key);
          const count = EVENTS.filter(evt =>
            filterMode === "type" ? evt.type === key : evt.conflict === key
          ).length;
          return (
            <div
              key={key}
              onClick={() => toggle(key)}
              style={{
                display: "flex", alignItems: "center", gap: 8, padding: "3px 0",
                cursor: "pointer", opacity: isHidden ? 0.3 : 1,
                transition: "opacity 0.2s",
              }}
            >
              <span style={{
                width: 10, height: 10, borderRadius: "50%",
                background: color, flexShrink: 0,
                boxShadow: isHidden ? "none" : `0 0 6px ${color}`,
              }} />
              <span style={{ color: "#d4d4d8", flex: 1 }}>{key}</span>
              <span style={{ color: "#71717a" }}>{count}</span>
            </div>
          );
        })}

        <div
          onClick={() => setHidden(new Set())}
          style={{
            marginTop: 8, textAlign: "center", color: "#71717a",
            cursor: "pointer", fontSize: 10, borderTop: "1px solid #3f3f46",
            paddingTop: 6,
          }}
          onMouseEnter={e => { (e.target as HTMLDivElement).style.color = "#fff"; }}
          onMouseLeave={e => { (e.target as HTMLDivElement).style.color = "#71717a"; }}
        >
          Show all
        </div>
      </div>
    </div>
  );
}

