import { useState, useMemo } from "react";
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
  AreaChart, Area, CartesianGrid,
} from "recharts";
import { Search, Skull, TrendingUp, TrendingDown, Globe, AlertTriangle, Filter } from "lucide-react";
import { CONFLICTS, getDailyDeaths, getDateString, getRegionData, getTrendData } from "./data/conflicts";
import ConflictCard from "./components/ConflictCard";

const SEVERITY_FILTERS = ["all", "major_war", "war", "conflict"] as const;
const TREND_FILTERS = ["all", "escalating", "stable", "de-escalating"] as const;

const severityLabels: Record<string, string> = {
  all: "All",
  major_war: "Major War",
  war: "War",
  conflict: "Conflict",
};

const CustomTooltip = ({ active, payload, label }: any) => {
  if (!active || !payload?.length) return null;
  return (
    <div className="bg-zinc-900 border border-zinc-700 px-2 py-1.5 text-[10px]">
      <p className="text-zinc-300 font-medium mb-0.5">{label}</p>
      {payload.map((p: any, i: number) => (
        <p key={i} style={{ color: p.color }}>
          {p.name}: {typeof p.value === "number" ? p.value.toLocaleString() : p.value}
        </p>
      ))}
    </div>
  );
};

export default function App() {
  const [search, setSearch] = useState("");
  const [severityFilter, setSeverityFilter] = useState<typeof SEVERITY_FILTERS[number]>("all");
  const [trendFilter, setTrendFilter] = useState<typeof TREND_FILTERS[number]>("all");
  const [showCharts, setShowCharts] = useState(true);

  const today = getDateString(0);

  // Compute today's deaths for each conflict and sort
  const conflictsWithDeaths = useMemo(() => {
    return CONFLICTS.map(c => ({
      ...c,
      todayDeaths: getDailyDeaths(c, today),
    })).sort((a, b) => b.todayDeaths - a.todayDeaths);
  }, [today]);

  // Summary stats
  const totalToday = useMemo(() => conflictsWithDeaths.reduce((s, c) => s + c.todayDeaths, 0), [conflictsWithDeaths]);
  const escalatingCount = CONFLICTS.filter(c => c.trend === "escalating").length;
  const activeCount = CONFLICTS.length;

  // Charts data
  const trendData = useMemo(() => getTrendData(CONFLICTS, 14), []);
  const regionData = useMemo(() => getRegionData(CONFLICTS, today), [today]);

  // Filtered conflicts
  const filtered = useMemo(() => {
    return conflictsWithDeaths.filter(c => {
      if (search) {
        const q = search.toLowerCase();
        const match = c.name.toLowerCase().includes(q) ||
          c.country.toLowerCase().includes(q) ||
          c.region.toLowerCase().includes(q) ||
          c.parties.some(p => p.toLowerCase().includes(q));
        if (!match) return false;
      }
      if (severityFilter !== "all" && c.severity !== severityFilter) return false;
      if (trendFilter !== "all" && c.trend !== trendFilter) return false;
      return true;
    });
  }, [conflictsWithDeaths, search, severityFilter, trendFilter]);

  const regionChartHeight = Math.max(160, regionData.length * 30);

  return (
    <div className="w-full h-full overflow-auto bg-zinc-950 text-zinc-100">
      {/* Summary Bar */}
      <div className="sticky top-0 z-10 bg-zinc-950 border-b border-zinc-800">
        <div className="grid grid-cols-3 gap-0 divide-x divide-zinc-800">
          <div className="px-4 py-3 flex items-center gap-3">
            <Skull className="w-5 h-5 text-red-400 shrink-0" />
            <div>
              <div className="text-[10px] text-zinc-500 uppercase tracking-wider">Est. Deaths Today</div>
              <div className="text-xl font-bold text-red-400">{totalToday.toLocaleString()}</div>
            </div>
          </div>
          <div className="px-4 py-3 flex items-center gap-3">
            <Globe className="w-5 h-5 text-blue-400 shrink-0" />
            <div>
              <div className="text-[10px] text-zinc-500 uppercase tracking-wider">Active Zones</div>
              <div className="text-xl font-bold text-blue-400">{activeCount}</div>
            </div>
          </div>
          <div className="px-4 py-3 flex items-center gap-3">
            <AlertTriangle className="w-5 h-5 text-orange-400 shrink-0" />
            <div>
              <div className="text-[10px] text-zinc-500 uppercase tracking-wider">Escalating</div>
              <div className="text-xl font-bold text-orange-400">{escalatingCount}</div>
            </div>
          </div>
        </div>
        <div className="px-3 py-1 text-[9px] text-zinc-600 border-t border-zinc-800/50">
          {today} · Estimates based on ACLED, UCDP & ICG conflict data methodologies · Daily variation is model-generated
        </div>
      </div>

      {/* Charts Toggle */}
      <div className="px-3 pt-3 pb-1">
        <button
          onClick={() => setShowCharts(!showCharts)}
          className="text-[10px] text-zinc-500 hover:text-zinc-300 flex items-center gap-1 transition-colors"
        >
          <TrendingUp className="w-3 h-3" />
          {showCharts ? "Hide Charts" : "Show Charts"}
        </button>
      </div>

      {/* Charts */}
      {showCharts && (
        <div className="px-3 pb-2 space-y-3">
          {/* 14-Day Trend */}
          <div className="border border-zinc-800 bg-zinc-900/30 p-3">
            <div className="text-[10px] text-zinc-500 uppercase tracking-wider mb-2 flex items-center gap-1">
              <TrendingUp className="w-3 h-3" /> 14-Day Global Death Toll Trend
            </div>
            <ResponsiveContainer width="100%" height={120}>
              <AreaChart data={trendData} margin={{ left: 0, right: 0, top: 5, bottom: 0 }}>
                <defs>
                  <linearGradient id="deathGrad" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#27272a" />
                <XAxis dataKey="date" tick={{ fontSize: 9, fill: "#52525b" }} axisLine={false} tickLine={false} />
                <YAxis tick={{ fontSize: 9, fill: "#52525b" }} axisLine={false} tickLine={false} width={40} />
                <Tooltip content={<CustomTooltip />} />
                <Area
                  type="monotone"
                  dataKey="deaths"
                  name="Est. Deaths"
                  stroke="#ef4444"
                  strokeWidth={2}
                  fill="url(#deathGrad)"
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>

          {/* Region Breakdown */}
          <div className="border border-zinc-800 bg-zinc-900/30 p-3">
            <div className="text-[10px] text-zinc-500 uppercase tracking-wider mb-2 flex items-center gap-1">
              <Globe className="w-3 h-3" /> Deaths by Region (Today)
            </div>
            <ResponsiveContainer width="100%" height={regionChartHeight}>
              <BarChart
                data={regionData}
                layout="vertical"
                margin={{ left: 5, right: 15, top: 0, bottom: 0 }}
              >
                <CartesianGrid strokeDasharray="3 3" stroke="#27272a" horizontal={false} />
                <XAxis type="number" tick={{ fontSize: 9, fill: "#52525b" }} axisLine={false} tickLine={false} />
                <YAxis
                  type="category"
                  dataKey="region"
                  tick={{ fontSize: 10, fill: "#a1a1aa" }}
                  width={120}
                  axisLine={false}
                  tickLine={false}
                  interval={0}
                />
                <Tooltip content={<CustomTooltip />} />
                <Bar
                  dataKey="deaths"
                  name="Est. Deaths"
                  fill="#ef4444"
                  radius={[0, 2, 2, 0]}
                  maxBarSize={18}
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}

      {/* Filters */}
      <div className="px-3 py-2 space-y-2 border-t border-zinc-800/50">
        {/* Search */}
        <div className="relative">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-zinc-500" />
          <input
            type="text"
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Search conflicts, countries, regions..."
            className="w-full bg-zinc-900 border border-zinc-800 text-zinc-200 text-xs pl-8 pr-3 py-1.5 focus:outline-none focus:border-zinc-600 placeholder:text-zinc-600"
          />
        </div>

        {/* Filter pills */}
        <div className="flex items-center gap-3 flex-wrap">
          <div className="flex items-center gap-1">
            <Filter className="w-3 h-3 text-zinc-600" />
            <span className="text-[9px] text-zinc-600 uppercase">Severity:</span>
            {SEVERITY_FILTERS.map(f => (
              <button
                key={f}
                onClick={() => setSeverityFilter(f)}
                className={`text-[9px] px-1.5 py-0.5 transition-colors ${
                  severityFilter === f
                    ? "bg-zinc-100 text-zinc-900 font-semibold"
                    : "bg-zinc-800/60 text-zinc-500 hover:text-zinc-300"
                }`}
              >
                {severityLabels[f]}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-1">
            <span className="text-[9px] text-zinc-600 uppercase">Trend:</span>
            {TREND_FILTERS.map(f => (
              <button
                key={f}
                onClick={() => setTrendFilter(f)}
                className={`text-[9px] px-1.5 py-0.5 capitalize transition-colors ${
                  trendFilter === f
                    ? "bg-zinc-100 text-zinc-900 font-semibold"
                    : "bg-zinc-800/60 text-zinc-500 hover:text-zinc-300"
                }`}
              >
                {f === "all" ? "All" : f}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Conflict List */}
      <div className="px-3 pb-3 space-y-1.5">
        <div className="flex items-center justify-between py-1">
          <span className="text-[10px] text-zinc-500">
            {filtered.length} conflict{filtered.length !== 1 ? "s" : ""} · Sorted by today's death toll
          </span>
          <span className="text-[10px] text-zinc-600">
            {filtered.reduce((s, c) => s + c.todayDeaths, 0).toLocaleString()} est. deaths today
          </span>
        </div>
        {filtered.map(c => (
          <ConflictCard key={c.id} conflict={c} />
        ))}
        {filtered.length === 0 && (
          <div className="text-center py-8 text-zinc-600 text-xs">
            No conflicts match your filters.
          </div>
        )}
      </div>

      {/* Footer */}
      <div className="px-3 py-2 border-t border-zinc-800 text-[9px] text-zinc-600 leading-relaxed">
