import { useMemo, useState } from "react";

const ESRI_TILE_URL =
  "https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile";

function latLonToTile(lat: number, lon: number, zoom: number) {
  const n = Math.pow(2, zoom);
  const x = Math.floor(((lon + 180) / 360) * n);
  const latRad = (lat * Math.PI) / 180;
  const y = Math.floor(
    ((1 - Math.log(Math.tan(latRad) + 1 / Math.cos(latRad)) / Math.PI) / 2) * n
  );
  return { x, y };
}

function latLonToFractionalTile(lat: number, lon: number, zoom: number) {
  const n = Math.pow(2, zoom);
  const fracX = ((lon + 180) / 360) * n;
  const latRad = (lat * Math.PI) / 180;
  const fracY =
    ((1 - Math.log(Math.tan(latRad) + 1 / Math.cos(latRad)) / Math.PI) / 2) * n;
  return { fracX, fracY };
}

interface Props {
  lat: number;
  lon: number;
  zoom: number;
  className?: string;
  showCrosshair?: boolean;
}

export default function SatellitePreview({
  lat,
  lon,
  zoom,
  className = "",
  showCrosshair = true,
}: Props) {
  const [loadedCount, setLoadedCount] = useState(0);

  const tiles = useMemo(() => {
    const { x: cx, y: cy } = latLonToTile(lat, lon, zoom);
    const { fracX, fracY } = latLonToFractionalTile(lat, lon, zoom);

    const TILE_SIZE = 256;
    const GRID_W = 4;
    const GRID_H = 3;

    const startX = cx - Math.floor(GRID_W / 2);
    const startY = cy - Math.floor(GRID_H / 2);

    const gridPixelX = (fracX - startX) * TILE_SIZE;
    const gridPixelY = (fracY - startY) * TILE_SIZE;

    const tileList: { x: number; y: number; left: number; top: number }[] = [];
    for (let row = 0; row < GRID_H; row++) {
      for (let col = 0; col < GRID_W; col++) {
        tileList.push({
          x: startX + col,
          y: startY + row,
          left: col * TILE_SIZE,
          top: row * TILE_SIZE,
        });
      }
    }

    return {
      tileList,
      gridPixelX,
      gridPixelY,
      gridW: GRID_W * TILE_SIZE,
      gridH: GRID_H * TILE_SIZE,
      total: GRID_W * GRID_H,
    };
  }, [lat, lon, zoom]);

  const allLoaded = loadedCount >= tiles.total;

  return (
    <div className={`overflow-hidden relative ${className}`}>
      {/* Loading skeleton */}
      {!allLoaded && (
        <div className="absolute inset-0 bg-zinc-900 animate-pulse flex items-center justify-center">
          <span className="text-zinc-700 text-[9px]">Loading imagery…</span>
        </div>
      )}

      {/* Tile grid — grayscale + boosted contrast for B&W military look */}
      <div
        className="absolute transition-opacity duration-300"
        style={{
          left: `calc(50% - ${tiles.gridPixelX}px)`,
          top: `calc(50% - ${tiles.gridPixelY}px)`,
          width: tiles.gridW,
          height: tiles.gridH,
          opacity: allLoaded ? 1 : 0.3,
          filter: "grayscale(100%) contrast(1.2) brightness(0.85)",
        }}
      >
        {tiles.tileList.map((t) => (
          <img
            key={`${t.x}-${t.y}`}
            src={`${ESRI_TILE_URL}/${zoom}/${t.y}/${t.x}`}
            className="absolute block"
            style={{
              left: t.left,
              top: t.top,
              width: 256,
              height: 256,
            }}
            loading="lazy"
            draggable={false}
            alt=""
            onLoad={() => setLoadedCount((c) => c + 1)}
          />
        ))}
      </div>

      {/* Vignette */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          background:
            "radial-gradient(ellipse at center, transparent 20%, rgba(9,9,11,0.5) 90%)",
        }}
      />

      {/* Scan lines overlay for OSINT feel */}
      <div
        className="absolute inset-0 pointer-events-none opacity-[0.04]"
        style={{
          backgroundImage:
            "repeating-linear-gradient(0deg, transparent, transparent 1px, rgba(255,255,255,0.1) 1px, rgba(255,255,255,0.1) 2px)",
          backgroundSize: "100% 3px",
        }}
      />

      {/* Crosshair */}
      {showCrosshair && allLoaded && (
        <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
          {/* Horizontal line */}
          <div className="absolute w-6 h-px bg-red-500/40" />
          {/* Vertical line */}
          <div className="absolute h-6 w-px bg-red-500/40" />
          {/* Center dot */}
          <div className="absolute w-1.5 h-1.5 rounded-full bg-red-500/60" />
        </div>
      )}
    </div>
  );
}

