    >
      {/* Header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "10px 16px",
          borderBottom: "1px solid rgba(63,63,70,0.5)",
          flexShrink: 0,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          <div
            style={{
              width: 12,
              height: 12,
              borderRadius: "50%",
              background: zone.color,
              boxShadow: `0 0 10px ${zone.color}60`,
            }}
          />
          <div>
            <div
              style={{
                color: "#f4f4f5",
                fontSize: "14px",
                fontWeight: 600,
              }}
            >
              {zone.name}
            </div>
            <div style={{ color: "#71717a", fontSize: "10px" }}>
              {zone.conflict} · {zone.region} · {zone.lat.toFixed(2)}°,{" "}
              {zone.lon.toFixed(2)}°
            </div>
          </div>
        </div>
        <button
          onClick={(e) => {
            e.stopPropagation();
            onClose();
          }}
          style={{
            color: "#a1a1aa",
            fontSize: "12px",
            padding: "6px 14px",
            border: "1px solid rgba(63,63,70,0.7)",
