import { useState, useEffect, useCallback } from "react";
import {
  Satellite,
  Flame,
  Eye,
  RefreshCw,
  Radio,
  Crosshair,
  Filter,
} from "lucide-react";
import { AnimatePresence, motion } from "framer-motion";
import SatellitePreview from "./components/SatellitePreview";
import DetailMap from "./components/DetailMap";
import { CONFLICT_ZONES, type ConflictZone } from "./types";

const STATUS_STYLES: Record<
  string,
  { bg: string; text: string; label: string; dot: string }
> = {
  critical: {
    bg: "bg-red-500/20",
    text: "text-red-400",
    label: "CRITICAL",
    dot: "bg-red-500",
  },
  intense: {
    bg: "bg-orange-500/20",
    text: "text-orange-400",
    label: "INTENSE",
    dot: "bg-orange-500",
  },
  escalating: {
    bg: "bg-yellow-500/20",
    text: "text-yellow-400",
    label: "ESCALATING",
    dot: "bg-yellow-500",
  },
  active: {
    bg: "bg-emerald-500/20",
    text: "text-emerald-400",
    label: "ACTIVE",
    dot: "bg-emerald-500",
  },
};

const ALL_STATUSES = ["critical", "intense", "escalating", "active"] as const;

interface FirmsData {
  [zoneId: string]: number;
}

function ZoneCard({
  zone,
  fireCount,
  onClick,
  index,
}: {
  zone: ConflictZone;
  fireCount: number;
  onClick: () => void;
  index: number;
}) {
  const status = STATUS_STYLES[zone.status];

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.35, delay: index * 0.04 }}
      onClick={onClick}
      className="relative w-full aspect-[16/10] overflow-hidden border border-zinc-800/80 hover:border-zinc-500/60 transition-all group cursor-pointer"
      role="button"
      tabIndex={0}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault();
          onClick();
        }
      }}
    >
      {/* Satellite imagery background */}
      <SatellitePreview
        lat={zone.lat}
        lon={zone.lon}
        zoom={zone.zoom}
        className="absolute inset-0 w-full h-full"
        showCrosshair={true}
      />

      {/* Bottom gradient */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          background:
            "linear-gradient(to top, rgba(9,9,11,0.97) 0%, rgba(9,9,11,0.75) 35%, rgba(9,9,11,0.2) 65%, rgba(9,9,11,0.1) 100%)",
        }}
      />

      {/* Top-left: Status badge */}
      <div className="absolute top-1.5 left-1.5 flex items-center gap-1">
        <span
          className={`px-1.5 py-0.5 text-[8px] font-bold tracking-widest ${status.bg} ${status.text} border border-current/20`}
        >
          {status.label}
        </span>
        {fireCount > 0 && (
          <span className="flex items-center gap-0.5 px-1.5 py-0.5 bg-orange-500/15 text-orange-400 text-[8px] font-medium border border-orange-500/20">
            <Flame className="w-2.5 h-2.5" />
            {fireCount}
          </span>
        )}
      </div>

      {/* Top-right: Pulsing live indicator */}
      <div className="absolute top-1.5 right-1.5 flex items-center gap-1">
        <span className="relative flex h-1.5 w-1.5">
          <span
            className="animate-ping absolute inline-flex h-full w-full rounded-full opacity-60"
