import { useState, useEffect, useCallback, useRef } from "react";
import { TrendingUp, TrendingDown, RefreshCw, AlertCircle, Minus } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
import { formatDistanceToNow } from "date-fns";

interface Commodity {
  symbol: string;
  name: string;
  category: "metals" | "energy" | "agriculture";
  unit: string;
}

interface CommodityPrice {
  symbol: string;
  name: string;
  category: string;
  unit: string;
  price: number | null;
  change: number | null;
  changePercent: number | null;
  error?: boolean;
}

const COMMODITIES: Commodity[] = [
  { symbol: "GC=F", name: "Gold", category: "metals", unit: "/oz" },
  { symbol: "SI=F", name: "Silver", category: "metals", unit: "/oz" },
  { symbol: "PL=F", name: "Platinum", category: "metals", unit: "/oz" },
  { symbol: "PA=F", name: "Palladium", category: "metals", unit: "/oz" },
  { symbol: "HG=F", name: "Copper", category: "metals", unit: "/lb" },
  { symbol: "CL=F", name: "WTI Crude Oil", category: "energy", unit: "/bbl" },
  { symbol: "BZ=F", name: "Brent Crude", category: "energy", unit: "/bbl" },
  { symbol: "NG=F", name: "Natural Gas", category: "energy", unit: "/MMBtu" },
  { symbol: "ZC=F", name: "Corn", category: "agriculture", unit: "/bu" },
  { symbol: "ZW=F", name: "Wheat", category: "agriculture", unit: "/bu" },
  { symbol: "ZS=F", name: "Soybeans", category: "agriculture", unit: "/bu" },
  { symbol: "KC=F", name: "Coffee", category: "agriculture", unit: "/lb" },
  { symbol: "SB=F", name: "Sugar", category: "agriculture", unit: "/lb" },
  { symbol: "CT=F", name: "Cotton", category: "agriculture", unit: "/lb" },
  { symbol: "CC=F", name: "Cocoa", category: "agriculture", unit: "/t" },
];

const CATEGORY_COLORS: Record<string, string> = {
  metals: "bg-yellow-500/20 text-yellow-400 border-yellow-500/30",
  energy: "bg-red-500/20 text-red-400 border-red-500/30",
  agriculture: "bg-green-500/20 text-green-400 border-green-500/30",
};

const CATEGORY_LABELS: Record<string, string> = {
  metals: "Metal",
  energy: "Energy",
  agriculture: "Agri",
};

async function fetchCommodityPrice(commodity: Commodity): Promise<CommodityPrice> {
  try {
    const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(commodity.symbol)}?interval=1d&range=5d`;
    const res = await fetch(`/api/proxy?url=${encodeURIComponent(url)}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();

    const result = data?.chart?.result?.[0];
    if (!result) throw new Error("No data");

    const meta = result.meta;
    const price = meta.regularMarketPrice ?? null;
    const prevClose = meta.chartPreviousClose ?? meta.previousClose ?? null;

    let change: number | null = null;
    let changePercent: number | null = null;

    if (price != null && prevClose != null && prevClose !== 0) {
      change = price - prevClose;
      changePercent = (change / prevClose) * 100;
    }

    return {
      symbol: commodity.symbol,
      name: commodity.name,
      category: commodity.category,
      unit: commodity.unit,
      price,
      change,
      changePercent,
    };
  } catch {
    return {
      symbol: commodity.symbol,
      name: commodity.name,
      category: commodity.category,
      unit: commodity.unit,
      price: null,
      change: null,
      changePercent: null,
      error: true,
    };
  }
}

function formatPrice(price: number | null, symbol: string): string {
  if (price == null) return "Ã¢â‚¬â€";
  // Cents-based commodities (corn, wheat, soybeans, coffee, sugar, cotton, cocoa)
  const centsSymbols = ["ZC=F", "ZW=F", "ZS=F", "KC=F", "SB=F", "CT=F", "CC=F"];
  if (centsSymbols.includes(symbol)) {
    return price.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + "Ã‚Â¢";
  }
  return "$" + price.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function formatChange(val: number | null): string {
  if (val == null) return "Ã¢â‚¬â€";
  const prefix = val > 0 ? "+" : "";
  return prefix + val.toFixed(2);
}

function formatChangePercent(val: number | null): string {
  if (val == null) return "Ã¢â‚¬â€";
  const prefix = val > 0 ? "+" : "";
  return prefix + val.toFixed(2) + "%";
}

export default function App() {
  const [prices, setPrices] = useState<CommodityPrice[]>([]);
  const [loading, setLoading] = useState(true);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const [countdown, setCountdown] = useState(60);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const countdownRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const fetchAll = useCallback(async (isManual = false) => {
    if (isManual) setRefreshing(true);

    try {
      const results = await Promise.all(COMMODITIES.map(fetchCommodityPrice));
      setPrices(results);
      setLastUpdated(new Date());
    } catch {
      // keep old data
    } finally {
      setLoading(false);
      setRefreshing(false);
      setCountdown(60);
    }
  }, []);

  useEffect(() => {
    fetchAll();
    intervalRef.current = setInterval(() => fetchAll(), 60000);
    countdownRef.current = setInterval(() => {
      setCountdown((c) => (c > 0 ? c - 1 : 60));
    }, 1000);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
      if (countdownRef.current) clearInterval(countdownRef.current);
    };
  }, [fetchAll]);

  const handleRefresh = () => {
    fetchAll(true);
    if (intervalRef.current) clearInterval(intervalRef.current);
    intervalRef.current = setInterval(() => fetchAll(), 60000);
  };

  const successCount = prices.filter((p) => !p.error && p.price != null).length;
  const errorCount = prices.filter((p) => p.error || p.price == null).length;

  return (
    <div className="w-full h-full flex flex-col overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between px-4 pt-3 pb-2 flex-shrink-0">
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1.5 text-zinc-500 text-xs">
            <span>{successCount}/{COMMODITIES.length} loaded</span>
            {errorCount > 0 && (
              <span className="text-red-400">Ã‚Â· {errorCount} failed</span>
            )}
          </div>
        </div>
        <div className="flex items-center gap-3">
          {lastUpdated && (
            <span className="text-zinc-500 text-xs">
              {formatDistanceToNow(lastUpdated, { addSuffix: true })}
            </span>
          )}
          <button
            onClick={handleRefresh}
            disabled={refreshing}
            className="flex items-center gap-1.5 text-xs text-zinc-400 hover:text-zinc-200 transition-colors disabled:opacity-50"
          >
            <RefreshCw className={cn("w-3 h-3", refreshing && "animate-spin")} />
            <span className="tabular-nums text-zinc-600">{countdown}s</span>
          </button>
        </div>
      </div>

      {/* Table */}
      <ScrollArea className="flex-1 px-2">
        <table className="w-full text-xs">
          <thead>
            <tr className="text-zinc-500 border-b border-zinc-800">
              <th className="text-left py-2 px-2 font-medium">Commodity</th>
              <th className="text-left py-2 px-1 font-medium w-14">Type</th>
              <th className="text-right py-2 px-2 font-medium">Price (USD)</th>
              <th className="text-right py-2 px-2 font-medium">Change</th>
              <th className="text-right py-2 px-2 font-medium">% Chg</th>
            </tr>
          </thead>
          <tbody>
            {loading
              ? Array.from({ length: 15 }).map((_, i) => (
                  <tr key={i} className="border-b border-zinc-800/50">
                    <td className="py-2.5 px-2">
                      <Skeleton className="h-4 w-24 bg-zinc-800" />
                    </td>
                    <td className="py-2.5 px-1">
                      <Skeleton className="h-4 w-12 bg-zinc-800" />
                    </td>
                    <td className="py-2.5 px-2">
                      <Skeleton className="h-4 w-16 bg-zinc-800 ml-auto" />
                    </td>
                    <td className="py-2.5 px-2">
                      <Skeleton className="h-4 w-14 bg-zinc-800 ml-auto" />
                    </td>
                    <td className="py-2.5 px-2">
                      <Skeleton className="h-4 w-14 bg-zinc-800 ml-auto" />
                    </td>
                  </tr>
                ))
              : prices.map((item) => {
                  const isUp = item.change != null && item.change > 0;
                  const isDown = item.change != null && item.change < 0;
                  const isFlat = item.change != null && item.change === 0;
                  const hasError = item.error || item.price == null;

                  return (
                    <tr
                      key={item.symbol}
                      className={cn(
                        "border-b border-zinc-800/50 transition-colors hover:bg-zinc-800/30",
                        hasError && "opacity-50"
                      )}
                    >
                      <td className="py-2 px-2">
                        <div className="flex items-center gap-2">
                          {isUp && <TrendingUp className="w-3 h-3 text-emerald-400 flex-shrink-0" />}
                          {isDown && <TrendingDown className="w-3 h-3 text-red-400 flex-shrink-0" />}
                          {(isFlat || hasError) && <Minus className="w-3 h-3 text-zinc-600 flex-shrink-0" />}
                          <span className="text-zinc-100 font-medium">{item.name}</span>
                        </div>
                      </td>
                      <td className="py-2 px-1">
                        <Badge
                          variant="outline"
                          className={cn(
                            "text-[10px] px-1.5 py-0 font-normal border",
                            CATEGORY_COLORS[item.category]
                          )}
                        >
                          {CATEGORY_LABELS[item.category]}
                        </Badge>
                      </td>
                      <td className="py-2 px-2 text-right">
                        <span className="text-zinc-100 tabular-nums">
                          {hasError ? (
                            <span className="flex items-center justify-end gap-1 text-zinc-500">
                              <AlertCircle className="w-3 h-3" /> N/A
                            </span>
                          ) : (
                            formatPrice(item.price, item.symbol)
                          )}
                        </span>
                        <div className="text-zinc-600 text-[10px]">{item.unit}</div>
                      </td>
                      <td
                        className={cn(
                          "py-2 px-2 text-right tabular-nums",
                          isUp && "text-emerald-400",
                          isDown && "text-red-400",
                          (isFlat || hasError) && "text-zinc-500"
                        )}
                      >
                        {formatChange(item.change)}
                      </td>
                      <td className="py-2 px-2 text-right">
                        {item.changePercent != null ? (
                          <span
                            className={cn(
                              "inline-flex items-center gap-0.5 tabular-nums px-1.5 py-0.5 text-[11px] font-medium",
                              isUp && "bg-emerald-500/15 text-emerald-400",
                              isDown && "bg-red-500/15 text-red-400",
                              isFlat && "bg-zinc-500/15 text-zinc-400"
                            )}
                          >
                            {formatChangePercent(item.changePercent)}
                          </span>
                        ) : (
                          <span className="text-zinc-500">Ã¢â‚¬â€</span>
                        )}
                      </td>
                    </tr>
                  );
                })}
          </tbody>
        </table>
      </ScrollArea>

      {/* Footer */}
      <div className="flex items-center justify-between px-4 py-2 text-[10px] text-zinc-600 border-t border-zinc-800 flex-shrink-0">
        <span>Source: Yahoo Finance Ã‚Â· Futures contracts</span>
        <div className="flex items-center gap-3">
          <span className="flex items-center gap-1">
            <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full inline-block" /> Up
          </span>
          <span className="flex items-center gap-1">
            <span className="w-1.5 h-1.5 bg-red-500 rounded-full inline-block" /> Down
          </span>
        </div>
      </div>
    </div>
  );
}

