import { TelegramPost, ChannelConfig } from "../types";

const PROXY = "/api/proxy?url=";

function parseTimestamp(timeEl: Element | null): Date {
  if (!timeEl) return new Date();
  const datetime = timeEl.getAttribute("datetime");
  if (datetime) return new Date(datetime);
  const text = timeEl.textContent?.trim() || "";
  const parsed = new Date(text);
  return isNaN(parsed.getTime()) ? new Date() : parsed;
}

function extractViews(msgEl: Element): string | null {
  const viewsEl = msgEl.querySelector(".tgme_widget_message_views");
  if (viewsEl) return viewsEl.textContent?.trim() || null;

  const infoEl = msgEl.querySelector(".tgme_widget_message_info");
  if (infoEl) {
    const spans = infoEl.querySelectorAll("span");
    for (const span of spans) {
      const text = span.textContent?.trim() || "";
      if (text.match(/[\d.]+[KMB]?$/i) && !text.includes(":")) {
        return text;
      }
    }
  }
  return null;
}

function extractText(msgEl: Element): { text: string; rawHtml: string } {
  const textEl = msgEl.querySelector(".tgme_widget_message_text");
  if (!textEl) {
    const fwd = msgEl.querySelector(".tgme_widget_message_forwarded_from");
    if (fwd) return { text: `[Forwarded] ${fwd.textContent?.trim() || ""}`, rawHtml: "" };

    const sticker = msgEl.querySelector(".tgme_widget_message_sticker");
    if (sticker) return { text: "[Sticker]", rawHtml: "" };

    return { text: "[Media]", rawHtml: "" };
  }

  const rawHtml = textEl.innerHTML || "";
  const text = textEl.textContent?.trim() || "";
  return { text, rawHtml };
}

function parseMessages(channel: ChannelConfig, doc: Document): TelegramPost[] {
  const posts: TelegramPost[] = [];

  const processMsg = (msg: Element) => {
    const postId = msg.getAttribute("data-post") || "";
    const { text, rawHtml } = extractText(msg);
    const timeEl = msg.querySelector("time");
    const timestamp = parseTimestamp(timeEl);
    const views = extractViews(msg);

    const hasPhoto = !!msg.querySelector(".tgme_widget_message_photo_wrap, .tgme_widget_message_photo");
    const hasVideo = !!msg.querySelector(".tgme_widget_message_video, .tgme_widget_message_video_player, .message_video_play, .tgme_widget_message_videothumb");
    const hasDocument = !!msg.querySelector(".tgme_widget_message_document");
    const hasVoice = !!msg.querySelector(".tgme_widget_message_voice, .tgme_widget_message_roundvideo");

    posts.push({
      id: `${channel.name}_${postId}`,
      channelName: channel.name,
      channelLabel: channel.label,
      text,
      rawHtml,
      timestamp,
      views,
      hasPhoto,
      hasVideo,
      hasDocument,
      hasVoice,
      link: `https://t.me/${postId}`,
      region: channel.region,
    });
  };

  const messageWraps = doc.querySelectorAll(".tgme_widget_message_wrap");

  if (messageWraps.length === 0) {
    const messages = doc.querySelectorAll("[data-post]");
    messages.forEach(processMsg);
  } else {
    messageWraps.forEach(wrap => {
      const msg = wrap.querySelector(".tgme_widget_message");
      if (msg) processMsg(msg);
    });
  }

  return posts;
}

export async function fetchChannelPosts(channel: ChannelConfig): Promise<TelegramPost[]> {
  const url = `https://t.me/s/${channel.name}`;

  try {
    const res = await fetch(PROXY + encodeURIComponent(url), {
      headers: { "Accept": "text/html" }
    });

    if (!res.ok) {
      console.warn(`Failed to fetch ${channel.name}: ${res.status}`);
      return [];
    }

    const html = await res.text();
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, "text/html");

    return parseMessages(channel, doc);
  } catch (err) {
    console.warn(`Error fetching ${channel.name}:`, err);
    return [];
  }
}

export async function fetchAllChannels(channels: ChannelConfig[]): Promise<TelegramPost[]> {
  const results = await Promise.allSettled(
    channels.map(ch => fetchChannelPosts(ch))
  );

  const allPosts: TelegramPost[] = [];
  results.forEach(result => {
    if (result.status === "fulfilled") {
      allPosts.push(...result.value);
    }
  });

  allPosts.sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime());

  return allPosts;
}

