import type { PopulationResponse, CountryData, GlobalStats, YoYChange } from '../types';
import { getCleanName } from './countries';

const PROXY = '/api/proxy?url=';
const API = 'https://api.unhcr.org/population/v1';

async function apiFetch<T>(path: string): Promise<T> {
  const url = `${API}${path}`;
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 15000);
  try {
    const res = await fetch(PROXY + encodeURIComponent(url), {
      signal: controller.signal,
      headers: { 'Accept': 'application/json' },
    });
    clearTimeout(timeout);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return res.json();
  } catch (e) {
    clearTimeout(timeout);
    throw e;
  }
}

function safeNum(v: any): number {
  if (v === null || v === undefined || v === '') return 0;
  const n = Number(v);
  return isNaN(n) ? 0 : n;
}

// Aggregate items by a key (coo or coa name)
function aggregateByCountry(
  items: any[],
  nameKey: string,
  codeKey: string
): CountryData[] {
  const map = new Map<string, CountryData>();

  for (const item of items) {
    const name = item[nameKey];
    const code = item[codeKey] || '';
    if (!name || name === 'Unknown' || name === 'Various' || name === 'Stateless') continue;

    const existing = map.get(name);
    const refugees = safeNum(item.refugees);
    const asylum_seekers = safeNum(item.asylum_seekers);
    const idps = safeNum(item.idps);
    const stateless = safeNum(item.stateless);

    if (existing) {
      existing.refugees += refugees;
      existing.asylum_seekers += asylum_seekers;
      existing.idps += idps;
      existing.stateless += stateless;
      existing.total = existing.refugees + existing.asylum_seekers + existing.idps + existing.stateless;
    } else {
      const total = refugees + asylum_seekers + idps + stateless;
      map.set(name, {
        name: getCleanName(name),
        code,
        refugees,
        asylum_seekers,
        idps,
        stateless,
        total,
      });
    }
  }

  return Array.from(map.values())
    .filter(c => c.total > 0)
    .sort((a, b) => b.total - a.total);
}

function computeGlobalStats(countries: CountryData[]): GlobalStats {
  return countries.reduce(
    (acc, c) => ({
      refugees: acc.refugees + c.refugees,
      asylum_seekers: acc.asylum_seekers + c.asylum_seekers,
      idps: acc.idps + c.idps,
      stateless: acc.stateless + c.stateless,
      total: acc.total + c.total,
    }),
    { refugees: 0, asylum_seekers: 0, idps: 0, stateless: 0, total: 0 }
  );
}

export interface FetchResult {
  originCountries: CountryData[];
  hostCountries: CountryData[];
  currentStats: GlobalStats;
  previousStats: GlobalStats | null;
  yoyChange: YoYChange | null;
  year: number;
  previousYear: number;
  dataPeriod: string; // e.g. "End-2024" or "Mid-2025"
}

// Try fetching multiple years to find the latest with data
async function fetchYearData(year: number, mode: 'coo' | 'coa'): Promise<{ items: any[]; year: number }> {
  const allKey = mode === 'coo' ? 'coo_all' : 'coa_all';
  const res = await apiFetch<PopulationResponse>(
    `/population/?year=${year}&${allKey}=true&limit=1000&columns[]=refugees&columns[]=asylum_seekers&columns[]=idps&columns[]=stateless`
  );
  return { items: res.items || [], year };
}

export async function fetchAllData(): Promise<FetchResult> {
  // Try 2024 first (latest full-year data expected), fall back to 2023
  const yearsToTry = [2024, 2023];

  let originItems: any[] = [];
  let hostItems: any[] = [];
  let usedYear = 2024;

  // Try to get data for the latest available year
  for (const year of yearsToTry) {
    try {
      const [originRes, hostRes] = await Promise.allSettled([
        fetchYearData(year, 'coo'),
        fetchYearData(year, 'coa'),
      ]);

      const oi = originRes.status === 'fulfilled' ? originRes.value.items : [];
      const hi = hostRes.status === 'fulfilled' ? hostRes.value.items : [];

      if (oi.length > 0 || hi.length > 0) {
        originItems = oi;
        hostItems = hi;
        usedYear = year;
        break;
      }
    } catch {
      continue;
    }
  }

  if (originItems.length === 0 && hostItems.length === 0) {
    throw new Error('No data returned from API');
  }

  // Fetch previous year for comparison
  const prevYear = usedYear - 1;
  let prevOriginItems: any[] = [];
  try {
    const prevRes = await fetchYearData(prevYear, 'coo');
    prevOriginItems = prevRes.items;
  } catch {
    // Previous year comparison data is optional
  }

  const originCountries = aggregateByCountry(originItems, 'coo_name', 'coo');
  const hostCountries = aggregateByCountry(hostItems, 'coa_name', 'coa');
  const prevOriginCountries = aggregateByCountry(prevOriginItems, 'coo_name', 'coo');

  const currentStats = computeGlobalStats(originCountries);
  const previousStats = prevOriginCountries.length > 0
    ? computeGlobalStats(prevOriginCountries)
    : null;

  // Stateless is typically reported by host country
  if (hostCountries.length > 0) {
    const hostStats = computeGlobalStats(hostCountries);
    if (hostStats.stateless > currentStats.stateless) {
      currentStats.stateless = hostStats.stateless;
      currentStats.total = currentStats.refugees + currentStats.asylum_seekers + currentStats.idps + currentStats.stateless;
    }
  }

  const yoyChange: YoYChange | null = previousStats
    ? {
        refugees: currentStats.refugees - previousStats.refugees,
        asylum_seekers: currentStats.asylum_seekers - previousStats.asylum_seekers,
        idps: currentStats.idps - previousStats.idps,
        stateless: currentStats.stateless - previousStats.stateless,
        total: currentStats.total - previousStats.total,
      }
    : null;

  return {
    originCountries,
    hostCountries,
    currentStats,
    previousStats,
    yoyChange,
    year: usedYear,
    previousYear: prevYear,
    dataPeriod: `End-${usedYear}`,
  };
}

