export default function App() {
  const [data, setData] = useState<FetchResult | null>(null);
  const [loading, setLoading] = useState(true);
  const [usingFallback, setUsingFallback] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [selectedCountry, setSelectedCountry] = useState<{ country: CountryData; type: 'origin' | 'host' } | null>(null);
  const [refreshing, setRefreshing] = useState(false);

  const loadData = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true);
    else setLoading(true);

    try {
      const result = await fetchAllData();
      if (result.currentStats.total > 0) {
        setData(result);
        setUsingFallback(false);
      } else {
        throw new Error('Empty data');
      }
    } catch (err: any) {
      console.warn('API fetch failed, using fallback:', err.message);
      setData(getFallbackData());
      setUsingFallback(true);
    } finally {
      setLoading(false);
      setRefreshing(false);
      setLastUpdated(new Date());
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const originChartData = useMemo(() => {
    if (!data) return [];
    return data.originCountries.slice(0, 15).map(c => ({
      name: c.name.length > 18 ? c.name.slice(0, 16) + '…' : c.name,
      fullName: c.name,
      refugees: c.refugees,
      idps: c.idps,
      asylum_seekers: c.asylum_seekers,
      total: c.total,
      code: c.code,
    }));
  }, [data]);

  const hostChartData = useMemo(() => {
    if (!data) return [];
    return data.hostCountries.slice(0, 15).map(c => ({
      name: c.name.length > 18 ? c.name.slice(0, 16) + '…' : c.name,
      fullName: c.name,
      refugees: c.refugees,
      idps: c.idps,
      asylum_seekers: c.asylum_seekers,
      total: c.total,
