        <span className="font-bold text-xs tracking-widest">{config.label}</span>
      </div>
      <div className="h-4 w-px bg-zinc-700" />
      <div className="flex items-center gap-4 text-xs text-zinc-400 flex-1">
        <span>
          <span className="text-red-400 font-bold">{criticalCount}</span> CRITICAL
        </span>
        <span>
          <span className="text-amber-400 font-bold">{conflictZoneCount}</span> CONFLICT ZONES
        </span>
        <span>
          <span className="text-zinc-200 font-bold">{totalCount}</span> ACTIVE NOTAMs
        </span>
      </div>
      <div className="flex items-center gap-1.5">
        <Activity size={12} className={config.text} />
        <span className={`text-[10px] ${config.text}`}>LIVE</span>
      </div>
    </div>
  );
}

