import { useState } from 'react';
import { formatDistanceToNow, format } from 'date-fns';
import { ChevronDown, ChevronUp, Clock, MapPin, Plane, AlertTriangle } from 'lucide-react';
import { NotamEntry, TYPE_COLORS, CONFLICT_ZONES } from '../types';

interface NotamListProps {
  notams: NotamEntry[];
}

function getTimeRemaining(to: string): string | null {
  const diff = new Date(to).getTime() - Date.now();
  if (diff <= 0) return null;
  if (diff < 3600000) return `${Math.ceil(diff / 60000)}m remaining`;
  if (diff < 86400000) return `${Math.ceil(diff / 3600000)}h remaining`;
  return `${Math.ceil(diff / 86400000)}d remaining`;
}

function isExpiringSoon(to: string): boolean {
  const diff = new Date(to).getTime() - Date.now();
  return diff > 0 && diff < 12 * 3600000;
}

export function NotamList({ notams }: NotamListProps) {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  return (
    <div className="space-y-1 py-1">
      {notams.length === 0 && (
        <div className="text-center text-zinc-500 py-12 text-xs">
          NO ACTIVE NOTAMs MATCHING FILTERS
        </div>
      )}
      {notams.map((n) => {
        const isExpanded = expandedId === n.id;
        const remaining = getTimeRemaining(n.effectiveTo);
        const expiring = isExpiringSoon(n.effectiveTo);
        const isConflict = CONFLICT_ZONES.some(z => n.country.includes(z) || n.location.includes(z));
        const color = TYPE_COLORS[n.type];

        return (
          <div
            key={n.id}
            className={`border transition-colors cursor-pointer ${
              isConflict
                ? 'border-red-600/40 bg-red-950/20 hover:bg-red-950/30'
                : 'border-zinc-800 bg-zinc-900/50 hover:bg-zinc-800/50'
            }`}
            onClick={() => setExpandedId(isExpanded ? null : n.id)}
            style={{ borderLeftWidth: 3, borderLeftColor: color }}
          >
            {/* Header row */}
            <div className="px-3 py-2 flex items-start gap-2">
              <div className="flex-1 min-w-0">
                {/* Top line: badges + notam ID */}
                <div className="flex items-center gap-1.5 flex-wrap mb-1">
                  <span
                    className="text-[9px] font-bold px-1.5 py-0.5 tracking-wider"
                    style={{ background: color + '22', color, border: `1px solid ${color}44` }}
                  >
                    {n.type}
                  </span>
                  <span className="text-[10px] text-zinc-400 font-bold">{n.notamId}</span>
                  {n.isNew && (
                    <span className="text-[9px] font-bold px-1.5 py-0.5 bg-amber-500 text-black tracking-wider animate-pulse">
                      NEW
                    </span>
                  )}
                  {n.severity === 'critical' && (
                    <span className="text-[9px] font-bold px-1.5 py-0.5 bg-red-600 text-white tracking-wider">
                      CRITICAL
                    </span>
                  )}
                  {expiring && (
                    <span className="text-[9px] px-1.5 py-0.5 bg-amber-900/50 text-amber-400 border border-amber-700/50">
                      EXPIRING
                    </span>
                  )}
                </div>

                {/* Location */}
                <div className="flex items-center gap-1.5 text-xs text-zinc-300 mb-0.5">
                  <MapPin size={10} className="text-zinc-500 flex-shrink-0" />
                  <span className="truncate">{n.location}</span>
                  <span className="text-zinc-600">|</span>
                  <span className="text-zinc-500 text-[10px]">{n.fir}</span>
                </div>

                {/* Time + altitude */}
                <div className="flex items-center gap-3 text-[10px] text-zinc-500">
                  <span className="flex items-center gap-1">
                    <Clock size={9} />
                    {format(new Date(n.effectiveFrom), 'dd MMM HH:mm')}z → {format(new Date(n.effectiveTo), 'dd MMM HH:mm')}z
                  </span>
                  <span className="flex items-center gap-1">
                    <Plane size={9} />
                    {n.lowerAlt} → {n.upperAlt}
                  </span>
                </div>

                {/* Countdown */}
                {remaining && (
                  <div className={`text-[10px] mt-0.5 ${expiring ? 'text-amber-400' : 'text-zinc-500'}`}>
                    ⏱ {remaining}
                  </div>
                )}

                {/* Description preview */}
                {!isExpanded && (
                  <div className="text-[10px] text-zinc-500 mt-1 truncate">
                    {n.description.slice(0, 120)}...
                  </div>
                )}
              </div>

              <div className="text-zinc-600 flex-shrink-0 mt-1">
                {isExpanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
              </div>
            </div>

            {/* Expanded content */}
            {isExpanded && (
              <div className="px-3 pb-3 border-t border-zinc-800/50">
                <div className="mt-2 text-[10px] text-zinc-500 mb-1">
                  ISSUED: {formatDistanceToNow(new Date(n.issuedAt))} ago
                </div>
                <pre className="text-[10px] text-amber-400/90 whitespace-pre-wrap break-words leading-relaxed bg-zinc-950/50 p-2 border border-zinc-800">
                  {n.rawText}
                </pre>
                <div className="mt-2 flex flex-wrap gap-1">
                  {n.keywords.map(kw => (
                    <span key={kw} className="text-[9px] px-1.5 py-0.5 bg-zinc-800 text-zinc-400 border border-zinc-700">
                      {kw}
                    </span>
                  ))}
                </div>
                {isConflict && (
                  <div className="mt-2 flex items-center gap-1.5 text-[10px] text-red-400">
                    <AlertTriangle size={10} />
                    KNOWN CONFLICT ZONE — ENHANCED MONITORING
                  </div>
                )}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

