import { useEffect, useRef } from 'react';
import { NotamEntry, TYPE_COLORS } from '../types';

interface TickerProps {
  notams: NotamEntry[];
}

export function Ticker({ notams }: TickerProps) {
  const recent = notams.slice(0, 15);

  const tickerText = recent.map(n => {
    return `▸ [${n.notamId}] ${n.type} — ${n.location}: ${n.description.slice(0, 80)}...`;
  }).join('     ');

  return (
    <div className="relative overflow-hidden bg-zinc-950 border-t border-zinc-800 h-7 flex items-center">
      <div className="absolute left-0 top-0 bottom-0 w-8 bg-gradient-to-r from-zinc-950 to-transparent z-10" />
      <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-zinc-950 to-transparent z-10" />
      <div className="ticker-track whitespace-nowrap text-[10px] text-amber-500/80 tracking-wide">
        {tickerText}
        {'     '}
        {tickerText}
      </div>
      <style>{`
        .ticker-track {
          display: inline-block;
          animation: ticker-scroll 120s linear infinite;
        }
        @keyframes ticker-scroll {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
      `}</style>
    </div>
  );
}

