import { RefreshCw, Clock } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { NotamType, Region, REGIONS, TYPE_COLORS } from '../types';

interface FilterBarProps {
  regionFilter: Region;
  typeFilter: NotamType | 'All';
  setRegionFilter: (r: Region) => void;
  setTypeFilter: (t: NotamType | 'All') => void;
  lastUpdated: Date | null;
  onRefresh: () => void;
  loading: boolean;
}

const TYPES: (NotamType | 'All')[] = ['All', 'MIL', 'CONFLICT', 'TFR', 'LAUNCH', 'VIP'];

export function FilterBar({
  regionFilter, typeFilter, setRegionFilter, setTypeFilter,
  lastUpdated, onRefresh, loading,
}: FilterBarProps) {
  return (
    <div className="flex items-center gap-2 flex-wrap text-[10px]">
      {/* Region filter */}
      <div className="flex items-center gap-0.5">
        <span className="text-zinc-500 mr-1 text-[9px] tracking-widest">RGN</span>
        {REGIONS.map(r => (
          <button
            key={r}
            onClick={() => setRegionFilter(r)}
            className={`px-2 py-1 border transition-colors ${
              regionFilter === r
                ? 'bg-amber-900/40 border-amber-600/50 text-amber-400'
                : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:text-zinc-300 hover:border-zinc-600'
            }`}
          >
            {r === 'Global' ? '🌐 ALL' : r === 'Asia-Pacific' ? 'APAC' : r.toUpperCase()}
          </button>
        ))}
      </div>

      <div className="h-4 w-px bg-zinc-700" />

      {/* Type filter */}
      <div className="flex items-center gap-0.5">
        <span className="text-zinc-500 mr-1 text-[9px] tracking-widest">TYPE</span>
        {TYPES.map(t => {
          const color = t === 'All' ? '#a1a1aa' : TYPE_COLORS[t];
          return (
            <button
              key={t}
              onClick={() => setTypeFilter(t)}
              className={`px-2 py-1 border transition-colors ${
                typeFilter === t
                  ? 'border-opacity-60'
                  : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:text-zinc-300 hover:border-zinc-600'
              }`}
              style={typeFilter === t ? {
                background: color + '22',
                borderColor: color + '66',
                color: color,
              } : undefined}
            >
              {t}
            </button>
          );
        })}
      </div>

      <div className="flex-1" />

      {/* Last updated + refresh */}
      <div className="flex items-center gap-2 text-zinc-500">
        {lastUpdated && (
          <span className="flex items-center gap-1 text-[9px]">
            <Clock size={9} />
            {formatDistanceToNow(lastUpdated)} ago
          </span>
        )}
        <button
          onClick={onRefresh}
          disabled={loading}
          className="p-1 border border-zinc-800 hover:border-zinc-600 text-zinc-500 hover:text-amber-400 transition-colors disabled:opacity-50"
        >
          <RefreshCw size={11} className={loading ? 'animate-spin' : ''} />
        </button>
      </div>
    </div>
  );
}

