import { useState, useRef, useEffect } from 'react';
import { Map, List, Radio } from 'lucide-react';
import { useNotams } from './hooks/useNotams';
import { AlertBanner } from './components/AlertBanner';
import { FilterBar } from './components/FilterBar';
import { NotamMap } from './components/NotamMap';
import { NotamList } from './components/NotamList';
import { Ticker } from './components/Ticker';
import { Skeleton } from '@/components/ui/skeleton';

export default function App() {
  const {
    notams,
    filteredNotams,
    loading,
    lastUpdated,
    regionFilter,
    typeFilter,
    setRegionFilter,
    setTypeFilter,
    refresh,
    criticalCount,
    alertLevel,
  } = useNotams();

  const [activeTab, setActiveTab] = useState<'map' | 'list'>('map');
  const conflictZoneCount = notams.filter(n => n.isConflictZone).length;

  const mainRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const updateHeight = () => {
      if (mainRef.current) {
        mainRef.current.getBoundingClientRect();
      }
    };
    updateHeight();
    window.addEventListener('resize', updateHeight);
    const timer = setTimeout(updateHeight, 100);
    return () => {
      window.removeEventListener('resize', updateHeight);
      clearTimeout(timer);
    };
  }, [loading]);

  if (loading && notams.length === 0) {
    return (
      <div className="w-full h-full flex flex-col gap-2 p-3 bg-zinc-950">
        <Skeleton className="h-10 w-full bg-zinc-800" />
        <Skeleton className="h-8 w-full bg-zinc-800" />
        <Skeleton className="flex-1 w-full bg-zinc-800" />
        <Skeleton className="h-7 w-full bg-zinc-800" />
      </div>
    );
  }

  return (
    <div className="w-full h-full flex flex-col bg-zinc-950 overflow-hidden">
      {/* Alert Banner */}
      <AlertBanner
        alertLevel={alertLevel}
        criticalCount={criticalCount}
        totalCount={notams.length}
        conflictZoneCount={conflictZoneCount}
      />

      {/* Filters */}
      <div className="px-3 py-2 border-b border-zinc-800/50">
        <FilterBar
          regionFilter={regionFilter}
          typeFilter={typeFilter}
          setRegionFilter={setRegionFilter}
          setTypeFilter={setTypeFilter}
          lastUpdated={lastUpdated}
          onRefresh={refresh}
          loading={loading}
        />
      </div>

      {/* Tab header */}
      <div className="px-3 pt-1.5 pb-1 flex items-center gap-0.5 shrink-0">
        <button
          onClick={() => setActiveTab('map')}
          className={`text-[10px] h-7 px-3 flex items-center gap-1.5 border transition-colors ${
            activeTab === 'map'
              ? 'bg-amber-900/30 border-amber-600/40 text-amber-400'
              : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:text-zinc-300 hover:border-zinc-600'
          }`}
        >
          <Map size={10} />
          MAP VIEW
        </button>
        <button
          onClick={() => setActiveTab('list')}
          className={`text-[10px] h-7 px-3 flex items-center gap-1.5 border transition-colors ${
            activeTab === 'list'
              ? 'bg-amber-900/30 border-amber-600/40 text-amber-400'
              : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:text-zinc-300 hover:border-zinc-600'
          }`}
        >
          <List size={10} />
          LIST VIEW
          <span className="text-[9px] bg-zinc-800 text-zinc-400 px-1.5 py-0 ml-1">{filteredNotams.length}</span>
        </button>
      </div>

      {/* Main content area */}
      <div ref={mainRef} className="flex-1 min-h-0 relative">
        {activeTab === 'map' && (
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, bottom: 0 }}>
            <NotamMap notams={filteredNotams} />
          </div>
        )}
        {activeTab === 'list' && (
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, bottom: 0, overflow: 'auto' }} className="px-2">
            <NotamList notams={filteredNotams} />
          </div>
        )}
      </div>

      {/* Bottom ticker */}
      <Ticker notams={notams} />

      {/* Data source notice */}
      <div className="px-3 py-1 bg-zinc-950 border-t border-zinc-900 flex items-center gap-2 text-[9px] text-zinc-600 shrink-0">
        <Radio size={8} className="text-amber-600" />
        <span>SIMULATED NOTAM FEED — BASED ON CURRENT KNOWN CONFLICT ZONES AND MILITARY ACTIVITY PATTERNS</span>
        <span className="ml-auto">AUTO-REFRESH: 5 MIN</span>
      </div>
    </div>
  );
}
